import{_ as t,c as o,o as e,ai as r}from"./chunks/framework.TS84ywiI.js";const _=JSON.parse('{"title":"如何找出某一天访问百度网站最多的 IP？","description":"","frontmatter":{},"headers":[],"relativePath":"big-data/find-top-1-ip.md","filePath":"big-data/find-top-1-ip.md"}'),i={name:"big-data/find-top-1-ip.md"};function n(l,a,s,p,d,h){return e(),o("div",null,a[0]||(a[0]=[r('<h1 id="如何找出某一天访问百度网站最多的-ip" tabindex="-1">如何找出某一天访问百度网站最多的 IP？ <a class="header-anchor" href="#如何找出某一天访问百度网站最多的-ip" aria-label="Permalink to &quot;如何找出某一天访问百度网站最多的 IP？&quot;">​</a></h1><h2 id="题目描述" tabindex="-1">题目描述 <a class="header-anchor" href="#题目描述" aria-label="Permalink to &quot;题目描述&quot;">​</a></h2><p>现有海量日志数据保存在一个超大文件中，该文件无法直接读入内存，要求从中提取某天访问百度次数最多的那个 IP。</p><h2 id="解答思路" tabindex="-1">解答思路 <a class="header-anchor" href="#解答思路" aria-label="Permalink to &quot;解答思路&quot;">​</a></h2><p>这道题只关心某一天访问百度最多的 IP，因此，可以首先对文件进行一次遍历，把这一天访问百度 IP 的相关信息记录到一个单独的大文件中。接下来采用的方法与上一题一样，大致就是先对 IP 进行哈希映射，接着使用 HashMap 统计重复 IP 的次数，最后计算出重复次数最多的 IP。</p><blockquote><p>注：这里只需要找出出现次数最多的 IP，可以不必使用堆，直接用一个变量 max 即可。</p></blockquote><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><ol><li>分而治之，进行哈希取余；</li><li>使用 HashMap 统计频数；</li><li>求解<strong>最大</strong>的 TopN 个，用<strong>小顶堆</strong>；求解<strong>最小</strong>的 TopN 个，用<strong>大顶堆</strong>。</li></ol>',8)]))}const P=t(i,[["render",n]]);export{_ as __pageData,P as default};
